# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

from flask import Flask, request, jsonify
import jwt
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'  # replace with a secret key of your choice

# Simple user model for demonstration purposes
users = {
    "user1": "password1",
    "user2": "password2"
}

def login(username, password):
    if username in users and users[username] == password:
        return jwt.encode({'username': username}, app.config['SECRET_KEY'], algorithm='HS256')
    return None

@app.route('/login', methods=['POST'])
def login_route():
    data = request.json
    token = login(data['username'], data['password'])
    if token is not None:
        return jsonify({'token': token.decode('UTF-8')})
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
def protected_route():
    try:
        token = request.headers.get('Authorization').split()[1]
        decoded_token = jwt.decode(token, app.config['SECRET_KEY'], algorithms='HS256')
        return jsonify({'message': f'Hello {decoded_token["username"]}!'})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)